# compute longest common substring between normalized strings
def longest_common_substring(a,b):
    # returns length of LCS substring (contiguous)
    m = [[0]*(1+len(b)) for _ in range(1+len(a))]
    longest = 0
    for i in range(1,1+len(a)):
        for j in range(1,1+len(b)):
            if a[i-1]==b[j-1]:
                m[i][j]=m[i-1][j-1]+1
                if m[i][j]>longest:
                    longest=m[i][j]
            else:
                m[i][j]=0
    return longest

